import{_ as e,c as t,o as s,ae as n}from"./chunks/framework.Ck3L_38O.js";const u=JSON.parse('{"title":"07 - Database Hash Tables ✸ YugabyteDB Database Talk (CMU Intro to Database Systems)","description":"","frontmatter":{},"headers":[],"relativePath":"course/CMU_15-445_Fall2025/lec7.md","filePath":"course/CMU_15-445_Fall2025/lec7.md"}'),h={name:"course/CMU_15-445_Fall2025/lec7.md"};function r(i,a,o,l,b,c){return s(),t("div",null,[...a[0]||(a[0]=[n('<h1 id="_07-database-hash-tables-✸-yugabytedb-database-talk-cmu-intro-to-database-systems" tabindex="-1">07 - Database Hash Tables ✸ YugabyteDB Database Talk (CMU Intro to Database Systems) <a class="header-anchor" href="#_07-database-hash-tables-✸-yugabytedb-database-talk-cmu-intro-to-database-systems" aria-label="Permalink to &quot;07 - Database Hash Tables ✸ YugabyteDB Database Talk (CMU Intro to Database Systems)&quot;">​</a></h1><h2 id="hash-functions" tabindex="-1">Hash Functions <a class="header-anchor" href="#hash-functions" aria-label="Permalink to &quot;Hash Functions&quot;">​</a></h2><p>目前被认为最快最先进的哈希算法是 <strong>Rapid Hash</strong> 。</p><h3 id="linear-probe-hashing" tabindex="-1">Linear Probe Hashing <a class="header-anchor" href="#linear-probe-hashing" aria-label="Permalink to &quot;Linear Probe Hashing&quot;">​</a></h3><p>线性探测法...</p><h3 id="cuckoo-hashing" tabindex="-1">Cuckoo Hashing <a class="header-anchor" href="#cuckoo-hashing" aria-label="Permalink to &quot;Cuckoo Hashing&quot;">​</a></h3><p>多哈希函数替代单函数：每个键通过 k 个独立哈希函数（通常 k=2 或更多）映射到 k 个可能的存储位置。<br> 插入新键时，检查其所有 k 个候选位置。若有空位，直接放入。若全被占用，则随机驱逐其中一个位置上的“老键”，将新键放入。被驱逐的“老键”需重新安置：用其 k 个哈希函数找新位置（避开刚被驱逐的位置）。若新位置被占，则递归驱逐，形成“链式反应”。终止条件：找到空位，或检测到循环（回到起点或超过最大尝试次数），此时触发扩容重建。</p><p>插入随机驱逐感觉反直觉...</p><h3 id="chained-hashing" tabindex="-1">Chained Hashing <a class="header-anchor" href="#chained-hashing" aria-label="Permalink to &quot;Chained Hashing&quot;">​</a></h3><p>链式存储法...</p><h3 id="extendible-hashing" tabindex="-1">Extendible Hashing <a class="header-anchor" href="#extendible-hashing" aria-label="Permalink to &quot;Extendible Hashing&quot;">​</a></h3><p>可扩展哈希是简历再链式存储法之上的，基本思想是让链式存储法无线增长的 bucket 变成，在 bucket 满了之后拆分，重新分配。<br> 哈希函数生成二进制数据，通过哈希值取前缀用于选择 bucket ，如果 bucket 满了，就将 bucket 里的数据拆分按照前缀，同时令 bucket 的大小翻倍，同时增加前缀的个数。</p><h3 id="linear-hashing" tabindex="-1">Linear Hashing <a class="header-anchor" href="#linear-hashing" aria-label="Permalink to &quot;Linear Hashing&quot;">​</a></h3><p><a href="https://blog.csdn.net/jackydai987/article/details/6673063" target="_blank" rel="noreferrer">线性哈希</a></p>',14)])])}const k=e(h,[["render",r]]);export{u as __pageData,k as default};
